// ─── TEAK LIPPING RATES ──────────────────────────────────────────────────────
const TEAK_LIPPING_RATES={"30mm":18,"35mm":20,"40mm":24,"45mm":26,"50mm":36,"55mm_120":40,"45mm_60":26,"45mm_120":26,"40mm_60":24};
// Map variant key → lipping rate (fire door 55mm uses 40, 45mm uses 26, 40mm uses 24)
function lippingRate(variant){return TEAK_LIPPING_RATES[variant]||null;}

// ─── DOOR CALCULATION ────────────────────────────────────────────────────────
function calculate(s){
  const wFt=toFt(s.width,s.unit), hFt=toFt(s.height,s.unit);
  if(!wFt||!hFt) return null;
  const area=wFt*hFt, qty=Math.max(1,parseInt(s.qty)||1), mPct=parseFloat(s.margin)||0;
  const dd=CATALOG[s.doorType], vd=dd?.variants[s.variant];
  if(!vd) return null;
  const isMR=dd.type==="mr", isFire=dd.type==="fire", is5509=s.doorType==="is5509", is3614=s.doorType==="is3614";
  const cores=vd.cores||0;
  let base=is3614?(s.int3614?vd.rateWith:vd.rateNo):vd.rate, rate=base;
  const bd=[{label:`Base — ${dd.label} ${vd.label}${is3614?(s.int3614?" (w/ intumescent)":" (w/o intumescent)"):""}`,value:base}];
  if(isMR&&s.isMarine){const v=cores*6;rate+=v;bd.push({label:`Marine Door (${cores}c×₹6)`,value:v});}
  if(is5509&&s.int5509){rate+=50;bd.push({label:"Intumescent strip (IS 5509)",value:50});}
  if(s.laminate){rate+=21;bd.push({label:"Laminate pressing (both sides)",value:21});}
  if(s.groove==="one"){rate+=11;bd.push({label:"Groove — one side",value:11});}
  if(s.groove==="both"){rate+=15;bd.push({label:"Groove — both sides",value:15});}
  if(s.laminateJoint){rate+=2;bd.push({label:"Laminate joint",value:2});}
  if(s.glassGap){const v=isFire?25:20;rate+=v;bd.push({label:"Glass gap",value:v});}
  if(s.rebate){rate+=10;bd.push({label:"Rebate (Badam)",value:10});}
  if(isMR&&s.plasticPatty){rate+=3;bd.push({label:"Plastic patty",value:3});}
  if(s.teakLipping){const lr=lippingRate(s.variant);if(lr){rate+=lr;bd.push({label:`Teak Lipping Patti`,value:lr});}}
  const isSmall=wFt<2||hFt<5, isBig=wFt>4||hFt>8; // <2ft wide OR <5ft tall
  if(isSmall){rate+=10;bd.push({label:"Small door",value:10});}
  if(isBig){const v=isFire?70:50;rate+=v;bd.push({label:"Big door surcharge",value:v});}
  if(qty<10){rate+=3;bd.push({label:"Multi-size",value:3});}
  rate+=15;bd.push({label:"Transport",value:15});
  const doorVal=rate*area*qty, mAmt=doorVal*(mPct/100), gst=(doorVal+mAmt)*0.18;
  const total=doorVal+mAmt+gst, perDoor=total/qty, preTaxPerDoor=(doorVal+mAmt)/qty;
  return {wFt,hFt,area,rate,bd,doorVal,mAmt,gst,total,perDoor,preTaxPerDoor,qty,isSmall,isBig};
}

// ─── FRAME CALCULATION ───────────────────────────────────────────────────────
function calculateFrame(s){
  let swIn,shIn;
  if(s.species==="teak_african"){
    const sec=TEAK_SECTIONS[s.teakSection]; if(!sec) return null;
    swIn=sec.w; shIn=sec.h;
  } else {
    swIn=toInchCeil(s.sectionW,s.sectionUnit);
    shIn=toInchCeil(s.sectionH,s.sectionUnit);
  }
  if(!swIn||!shIn) return null;
  const wFt=toFeetQ(s.openW,s.openUnit), hFt=toFeetQ(s.openH,s.openUnit);
  if(!wFt||!hFt) return null;
  const hornExtra=s.horns?0.5:0;
  const runningFt=2*hFt+wFt+hornExtra;
  const cubicRaw=(swIn*shIn*runningFt)/144;
  const wastage=cubicRaw*0.10;
  const cubicFt=cubicRaw+wastage;
  let rate=null;
  if(s.species==="red_meranti"){
    rate=1200;
  } else {
    const sec=TEAK_SECTIONS[s.teakSection]; if(!sec) return null;
    for(const b of sec.rates){ if(hFt<=b.maxH){rate=b.rate;break;} }
    if(!rate) return null;
  }
  const transport=parseFloat(s.transport)||100;
  const mPct=parseFloat(s.margin)||0;
  const woodCost=cubicFt*rate;
  const subtotal=woodCost+250+transport;
  const marginAmt=subtotal*(mPct/100);
  const preTax=subtotal+marginAmt;
  const gst=preTax*0.18;
  const total=preTax+gst;
  const qty=Math.max(1,parseInt(s.qty)||1);
  return {swIn,shIn,wFt,hFt,runningFt,hornExtra,cubicRaw,wastage,cubicFt,rate,woodCost,transport,subtotal,marginAmt,preTax,gst,total,perFrame:preTax,totalPerFrame:total,qty};
}


