// ─── TOG COMPONENT ───────────────────────────────────────────────────────────
function Tog({on,set,label,detail}){
  return <div className={"tog"+(on?" on":"")} onClick={()=>set(!on)}>
    <div className={"pill"+(on?" on":"")}/>
    <span style={{fontSize:12}}>{label}</span>
    {detail&&<span style={{marginLeft:"auto",fontSize:10,color:N.sub}}>{detail}</span>}
  </div>;
}

